#include <bits/stdc++.h>
using namespace std;
struct Node{
    int x,y;
}n1,n2;
int di[12][2]={{-2,-1},{-1,-2},{1,2},{2,1},{-1,2},{2,-1},{1,-2},{-2,1},{-2,-2},{2,2},{-2,2},{2,-2}};
void bfs(int sx,int sy){
    int mark[102][102];
    memset(mark,0,sizeof(mark));
    queue<int> qx,qy;
    qx.push(sx);
    qy.push(sy);
    mark[sx][sy]=1;
    while(qx.size()){
        int fx=qx.front(),fy=qy.front();
        qx.pop(),qy.pop();
        for(int i=0;i<12;i++){
            int xx=fx+di[i][0],yy=fy+di[i][1];
            if(xx>0 && yy>0 && xx<101 && yy<101 && !mark[xx][yy])
                mark[xx][yy]=mark[fx][fy]+1,qx.push(xx),qy.push(yy);
        }
    }
    cout<<mark[1][1]-1<<endl;
}
int main(){
    cin>>n1.x>>n1.y>>n2.x>>n2.y;
    bfs(n1.x,n1.y);
    bfs(n2.x,n2.y);
    return 0;
}
